class UndoManager {
  private undoStack: string[] = [];
  private redoStack: string[] = [];
  push(state: string) { this.undoStack.push(state); this.redoStack = []; }
  undo() { const s = this.undoStack.pop(); if (s) this.redoStack.push(s); return this.undoStack.at(-1); }
  redo() { const s = this.redoStack.pop(); if (s) this.undoStack.push(s); return s; }
}

class RouterHistory {
  private back: string[] = [location.href];
  private forward: string[] = [];
  navigate(url: string) { this.back.push(url); this.forward = []; }
  goBack() { if (this.back.length > 1) { this.forward.push(this.back.pop()!); } }
  goForward() { if (this.forward.length) { this.back.push(this.forward.pop()!); } }
}

