function validateTags(s: string): boolean {
  const stack: string[] = [];
  const matches = s.matchAll(/<\/?([a-zA-Z]+)>/g);
  for (const [, tag, name] of Array.from(matches).map(m => [m[0], m[0].startsWith('</') ? null : m[1], m[1]])) {
    if (!tag.startsWith('</')) stack.push(name as string);
    else if (stack.pop() !== name) return false;
  }
  return stack.length === 0;
}

class RouterHistory {
  private backStack: string[];
  private forwardStack: string[] = [];
  constructor(initial: string) { this.backStack = [initial]; }
  get current() { return this.backStack[this.backStack.length - 1]; }
  navigate(url: string) { this.backStack.push(url); this.forwardStack = []; }
  back() {
    if (this.backStack.length > 1) this.forwardStack.push(this.backStack.pop()!);
    return this.current;
  }
  forward() {
    if (this.forwardStack.length) this.backStack.push(this.forwardStack.pop()!);
    return this.current;
  }
}
